import{_ as t,o as a,c as i,ag as o}from"./chunks/framework.BBBcTwIo.js";const p=JSON.parse('{"title":"Zustand Store API Reference","description":"","frontmatter":{},"headers":[],"relativePath":"api-store.md","filePath":"api-store.md"}'),d={name:"api-store.md"};function s(r,e,n,l,c,h){return a(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="zustand-store-api-reference" tabindex="-1">Zustand Store API Reference <a class="header-anchor" href="#zustand-store-api-reference" aria-label="Permalink to &quot;Zustand Store API Reference&quot;">​</a></h1><p>Complete function-level documentation for <code>useHeadstoneStore</code> (<code>lib/headstone-store.ts</code>).</p><h2 id="type-definitions-headstone-store-types-ts" tabindex="-1">Type Definitions (<code>headstone-store.types.ts</code>) <a class="header-anchor" href="#type-definitions-headstone-store-types-ts" aria-label="Permalink to &quot;Type Definitions (`headstone-store.types.ts`)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Type</th><th>Description</th></tr></thead><tbody><tr><td><code>Line</code></td><td>Inscription text with <code>id</code>, <code>text</code>, <code>sizeMm</code>, <code>font</code>, <code>color</code>, <code>xPos</code>, <code>yPos</code>, <code>rotationDeg</code>, <code>surface</code>, <code>baseWidthMm</code>, <code>baseHeightMm</code></td></tr><tr><td><code>Part</code></td><td><code>&#39;headstone&#39; | &#39;base&#39; | &#39;ledger&#39; | &#39;kerbset&#39; | null</code></td></tr><tr><td><code>Material</code></td><td>Texture/material with <code>id</code>, <code>name</code>, <code>image</code>, <code>category</code>, <code>textureUrl</code>, <code>thumbnailUrl</code></td></tr><tr><td><code>ShapeOption</code></td><td>Shape variant with <code>id</code>, <code>name</code>, <code>category</code>, <code>previewUrl</code>, <code>maskKey</code></td></tr><tr><td><code>BorderOption</code></td><td>Border style with <code>svgUrl</code> for plaques</td></tr><tr><td><code>MotifCatalogItem</code></td><td>Motif SVG with pricing info</td></tr><tr><td><code>AdditionKind</code></td><td><code>&#39;statue&#39; | &#39;vase&#39; | &#39;application&#39;</code></td></tr><tr><td><code>PanelName</code></td><td><code>&#39;shape&#39; | &#39;size&#39; | &#39;material&#39; | &#39;inscription&#39; | &#39;additions&#39; | &#39;addition&#39; | &#39;motifs&#39; | &#39;motif&#39; | &#39;image&#39; | &#39;emblems&#39; | &#39;emblem&#39; | &#39;checkprice&#39; | &#39;designs&#39; | null</code></td></tr><tr><td><code>LinePatch</code></td><td>Partial update: <code>text</code>, <code>font</code>, <code>sizeMm</code>, <code>rotationDeg</code>, <code>xPos</code>, <code>yPos</code>, <code>color</code></td></tr></tbody></table><hr><h2 id="product-setup-initialization" tabindex="-1">Product Setup &amp; Initialization <a class="header-anchor" href="#product-setup-initialization" aria-label="Permalink to &quot;Product Setup &amp; Initialization&quot;">​</a></h2><h3 id="setcatalog-catalog-catalogdata-void" tabindex="-1"><code>setCatalog(catalog: CatalogData): void</code> <a class="header-anchor" href="#setcatalog-catalog-catalogdata-void" aria-label="Permalink to &quot;`setCatalog(catalog: CatalogData): void`&quot;">​</a></h3><p>Sets the complete product catalog XML data (shapes, materials, pricing) for the selected product.</p><h3 id="setproductid-id-string-promise-void" tabindex="-1"><code>setProductId(id: string): Promise&lt;void&gt;</code> <a class="header-anchor" href="#setproductid-id-string-promise-void" aria-label="Permalink to &quot;`setProductId(id: string): Promise&lt;void&gt;`&quot;">​</a></h3><p><strong>Async.</strong> Fetches and parses the product catalog XML for the given product ID. Recalculates all dimension constraints, material lists, shape limits, base/ledger visibility based on product type. Rescales existing inscriptions and motifs to fit new constraints. Loads inscription and motif pricing models.</p><p><strong>Side effects:</strong> Clears old catalog → updates <code>materials</code>, <code>shapes</code>, dimensions, thickness, visibility flags → rescales inscriptions/motifOffsets → updates material URLs → sets color defaults → loads pricing.</p><h3 id="setmaterials-materials-material-void" tabindex="-1"><code>setMaterials(materials: Material[]): void</code> <a class="header-anchor" href="#setmaterials-materials-material-void" aria-label="Permalink to &quot;`setMaterials(materials: Material[]): void`&quot;">​</a></h3><p>Sets available material/texture options for the current product.</p><h3 id="setshapes-shapes-shapeoption-void" tabindex="-1"><code>setShapes(shapes: ShapeOption[]): void</code> <a class="header-anchor" href="#setshapes-shapes-shapeoption-void" aria-label="Permalink to &quot;`setShapes(shapes: ShapeOption[]): void`&quot;">​</a></h3><p>Sets available shape options (oval, circle, portrait, landscape, etc.).</p><h3 id="setborders-borders-borderoption-void" tabindex="-1"><code>setBorders(borders: BorderOption[]): void</code> <a class="header-anchor" href="#setborders-borders-borderoption-void" aria-label="Permalink to &quot;`setBorders(borders: BorderOption[]): void`&quot;">​</a></h3><p>Sets available border styles (for plaques only).</p><h3 id="setmotifscatalog-motifs-motifcatalogitem-void" tabindex="-1"><code>setMotifsCatalog(motifs: MotifCatalogItem[]): void</code> <a class="header-anchor" href="#setmotifscatalog-motifs-motifcatalogitem-void" aria-label="Permalink to &quot;`setMotifsCatalog(motifs: MotifCatalogItem[]): void`&quot;">​</a></h3><p>Sets the catalog of available motifs with pricing.</p><h3 id="setprojectmeta-meta-projectid-string-null-title-string-null-void" tabindex="-1"><code>setProjectMeta(meta: { projectId?: string | null; title?: string | null }): void</code> <a class="header-anchor" href="#setprojectmeta-meta-projectid-string-null-title-string-null-void" aria-label="Permalink to &quot;`setProjectMeta(meta: { projectId?: string | null; title?: string | null }): void`&quot;">​</a></h3><p>Sets/updates current project metadata (ID and title) for save/load tracking.</p><hr><h2 id="headstone-dimensions" tabindex="-1">Headstone Dimensions <a class="header-anchor" href="#headstone-dimensions" aria-label="Permalink to &quot;Headstone Dimensions&quot;">​</a></h2><h3 id="setwidthmm-v-number-void" tabindex="-1"><code>setWidthMm(v: number): void</code> <a class="header-anchor" href="#setwidthmm-v-number-void" aria-label="Permalink to &quot;`setWidthMm(v: number): void`&quot;">​</a></h3><p>Sets headstone width, clamped to <code>[minWidthMm, maxWidthMm]</code>. Enforces full-monument cascade: if base becomes narrower than headstone, base + kerbset width is increased to <code>headstone + 200mm</code>, ledger set to headstone width. Triggers inscription cost recalc.</p><h3 id="setheightmm-v-number-void" tabindex="-1"><code>setHeightMm(v: number): void</code> <a class="header-anchor" href="#setheightmm-v-number-void" aria-label="Permalink to &quot;`setHeightMm(v: number): void`&quot;">​</a></h3><p>Sets headstone height, clamped to <code>[minHeightMm, maxHeightMm]</code>.</p><h3 id="setuprightthickness-thickness-number-void" tabindex="-1"><code>setUprightThickness(thickness: number): void</code> <a class="header-anchor" href="#setuprightthickness-thickness-number-void" aria-label="Permalink to &quot;`setUprightThickness(thickness: number): void`&quot;">​</a></h3><p>Sets upright headstone thickness (depth), clamped to <code>[minThicknessMm, maxThicknessMm]</code>.</p><h3 id="setslantthickness-thickness-number-void" tabindex="-1"><code>setSlantThickness(thickness: number): void</code> <a class="header-anchor" href="#setslantthickness-thickness-number-void" aria-label="Permalink to &quot;`setSlantThickness(thickness: number): void`&quot;">​</a></h3><p>Sets slant headstone thickness, clamped to <code>[minThicknessMm, maxThicknessMm]</code>.</p><h3 id="setheadstonestyle-style-upright-slant-void" tabindex="-1"><code>setHeadstoneStyle(style: &#39;upright&#39; | &#39;slant&#39;): void</code> <a class="header-anchor" href="#setheadstonestyle-style-upright-slant-void" aria-label="Permalink to &quot;`setHeadstoneStyle(style: &#39;upright&#39; | &#39;slant&#39;): void`&quot;">​</a></h3><p>Switches between upright and slant headstone styles.</p><hr><h2 id="base-dimensions" tabindex="-1">Base Dimensions <a class="header-anchor" href="#base-dimensions" aria-label="Permalink to &quot;Base Dimensions&quot;">​</a></h2><h3 id="setbasewidthmm-v-number-void" tabindex="-1"><code>setBaseWidthMm(v: number): void</code> <a class="header-anchor" href="#setbasewidthmm-v-number-void" aria-label="Permalink to &quot;`setBaseWidthMm(v: number): void`&quot;">​</a></h3><p>Sets base width, clamped so base ≥ headstone width. <strong>Cascade:</strong> <code>kerbWidthMm = baseWidthMm</code>, <code>ledgerWidthMm = baseWidthMm - 200</code>.</p><h3 id="setbaseheightmm-v-number-void" tabindex="-1"><code>setBaseHeightMm(v: number): void</code> <a class="header-anchor" href="#setbaseheightmm-v-number-void" aria-label="Permalink to &quot;`setBaseHeightMm(v: number): void`&quot;">​</a></h3><p>Sets base height, clamped to valid range. <strong>Cascade:</strong> <code>kerbHeightMm = baseHeightMm - 100</code>.</p><h3 id="setbasethickness-thickness-number-void" tabindex="-1"><code>setBaseThickness(thickness: number): void</code> <a class="header-anchor" href="#setbasethickness-thickness-number-void" aria-label="Permalink to &quot;`setBaseThickness(thickness: number): void`&quot;">​</a></h3><p>Sets base depth, clamped to <code>[minThicknessMm, maxThicknessMm]</code>.</p><h3 id="setbasefinish-finish-default-rock-pitch-void" tabindex="-1"><code>setBaseFinish(finish: &#39;default&#39; | &#39;rock-pitch&#39;): void</code> <a class="header-anchor" href="#setbasefinish-finish-default-rock-pitch-void" aria-label="Permalink to &quot;`setBaseFinish(finish: &#39;default&#39; | &#39;rock-pitch&#39;): void`&quot;">​</a></h3><p>Sets base finish/texture variant.</p><h3 id="setshowbase-showbase-boolean-void" tabindex="-1"><code>setShowBase(showBase: boolean): void</code> <a class="header-anchor" href="#setshowbase-showbase-boolean-void" aria-label="Permalink to &quot;`setShowBase(showBase: boolean): void`&quot;">​</a></h3><p>Toggles base visibility. Auto-adjusts <code>editingObject</code> if currently editing hidden base.</p><hr><h2 id="ledger-kerbset-dimensions-full-monument" tabindex="-1">Ledger &amp; Kerbset Dimensions (Full Monument) <a class="header-anchor" href="#ledger-kerbset-dimensions-full-monument" aria-label="Permalink to &quot;Ledger &amp; Kerbset Dimensions (Full Monument)&quot;">​</a></h2><h3 id="setledgerwidthmm-v-number-void" tabindex="-1"><code>setLedgerWidthMm(v: number): void</code> <a class="header-anchor" href="#setledgerwidthmm-v-number-void" aria-label="Permalink to &quot;`setLedgerWidthMm(v: number): void`&quot;">​</a></h3><p>Sets ledger width. <strong>Cascade:</strong> <code>baseWidthMm = ledger + 200</code>, <code>kerbWidthMm = ledger + 200</code>.</p><h3 id="setledgerheightmm-v-number-void" tabindex="-1"><code>setLedgerHeightMm(v: number): void</code> <a class="header-anchor" href="#setledgerheightmm-v-number-void" aria-label="Permalink to &quot;`setLedgerHeightMm(v: number): void`&quot;">​</a></h3><p>Sets ledger thickness.</p><h3 id="setledgerdepthmm-v-number-void" tabindex="-1"><code>setLedgerDepthMm(v: number): void</code> <a class="header-anchor" href="#setledgerdepthmm-v-number-void" aria-label="Permalink to &quot;`setLedgerDepthMm(v: number): void`&quot;">​</a></h3><p>Sets ledger depth (front-to-back). <strong>Cascade:</strong> <code>kerbDepthMm = ledger + 120</code>.</p><h3 id="setshowledger-v-boolean-void" tabindex="-1"><code>setShowLedger(v: boolean): void</code> <a class="header-anchor" href="#setshowledger-v-boolean-void" aria-label="Permalink to &quot;`setShowLedger(v: boolean): void`&quot;">​</a></h3><p>Toggles ledger visibility. Auto-adjusts <code>editingObject</code>.</p><h3 id="setkerbwidthmm-v-number-void" tabindex="-1"><code>setKerbWidthMm(v: number): void</code> <a class="header-anchor" href="#setkerbwidthmm-v-number-void" aria-label="Permalink to &quot;`setKerbWidthMm(v: number): void`&quot;">​</a></h3><p>Sets kerbset width. <strong>Cascade:</strong> <code>baseWidthMm = kerbWidthMm</code>, <code>ledgerWidthMm = kerb - 200</code>.</p><h3 id="setkerbheightmm-v-number-void" tabindex="-1"><code>setKerbHeightMm(v: number): void</code> <a class="header-anchor" href="#setkerbheightmm-v-number-void" aria-label="Permalink to &quot;`setKerbHeightMm(v: number): void`&quot;">​</a></h3><p>Sets kerbset height. <strong>Cascade:</strong> <code>baseHeightMm = kerb + 100</code>.</p><h3 id="setkerbdepthmm-v-number-void" tabindex="-1"><code>setKerbDepthMm(v: number): void</code> <a class="header-anchor" href="#setkerbdepthmm-v-number-void" aria-label="Permalink to &quot;`setKerbDepthMm(v: number): void`&quot;">​</a></h3><p>Sets kerbset depth. <strong>Cascade:</strong> <code>ledgerDepthMm = kerb - 120</code>.</p><h3 id="setshowkerbset-v-boolean-void" tabindex="-1"><code>setShowKerbset(v: boolean): void</code> <a class="header-anchor" href="#setshowkerbset-v-boolean-void" aria-label="Permalink to &quot;`setShowKerbset(v: boolean): void`&quot;">​</a></h3><p>Toggles kerbset visibility. Auto-adjusts <code>editingObject</code>.</p><hr><h2 id="materials-textures" tabindex="-1">Materials &amp; Textures <a class="header-anchor" href="#materials-textures" aria-label="Permalink to &quot;Materials &amp; Textures&quot;">​</a></h2><h3 id="setmaterialurl-url-string-void" tabindex="-1"><code>setMaterialUrl(url: string): void</code> <a class="header-anchor" href="#setmaterialurl-url-string-void" aria-label="Permalink to &quot;`setMaterialUrl(url: string): void`&quot;">​</a></h3><p>Sets the base/default material texture URL; normalizes and validates URL format.</p><h3 id="setheadstonematerialurl-url-string-void" tabindex="-1"><code>setHeadstoneMaterialUrl(url: string): void</code> <a class="header-anchor" href="#setheadstonematerialurl-url-string-void" aria-label="Permalink to &quot;`setHeadstoneMaterialUrl(url: string): void`&quot;">​</a></h3><p>Sets headstone-specific texture URL.</p><h3 id="setbasematerialurl-url-string-void" tabindex="-1"><code>setBaseMaterialUrl(url: string): void</code> <a class="header-anchor" href="#setbasematerialurl-url-string-void" aria-label="Permalink to &quot;`setBaseMaterialUrl(url: string): void`&quot;">​</a></h3><p>Sets base-specific texture URL. Sets <code>baseSwapping = true</code> flag to trigger animation.</p><h3 id="setledgermaterialurl-url-string-void" tabindex="-1"><code>setLedgerMaterialUrl(url: string): void</code> <a class="header-anchor" href="#setledgermaterialurl-url-string-void" aria-label="Permalink to &quot;`setLedgerMaterialUrl(url: string): void`&quot;">​</a></h3><p>Sets ledger-specific texture URL.</p><h3 id="setkerbsetmaterialurl-url-string-void" tabindex="-1"><code>setKerbsetMaterialUrl(url: string): void</code> <a class="header-anchor" href="#setkerbsetmaterialurl-url-string-void" aria-label="Permalink to &quot;`setKerbsetMaterialUrl(url: string): void`&quot;">​</a></h3><p>Sets kerbset-specific texture URL.</p><h3 id="setbaseswapping-swapping-boolean-void" tabindex="-1"><code>setBaseSwapping(swapping: boolean): void</code> <a class="header-anchor" href="#setbaseswapping-swapping-boolean-void" aria-label="Permalink to &quot;`setBaseSwapping(swapping: boolean): void`&quot;">​</a></h3><p>Enables/disables material swap animation flag.</p><hr><h2 id="shapes-borders" tabindex="-1">Shapes &amp; Borders <a class="header-anchor" href="#shapes-borders" aria-label="Permalink to &quot;Shapes &amp; Borders&quot;">​</a></h2><h3 id="setshapeurl-url-string-void" tabindex="-1"><code>setShapeUrl(url: string): void</code> <a class="header-anchor" href="#setshapeurl-url-string-void" aria-label="Permalink to &quot;`setShapeUrl(url: string): void`&quot;">​</a></h3><p>Sets the headstone shape SVG URL. Auto-updates dimensions from catalog if matching shape is found. Attempts to match shape by filename or catalog code.</p><h3 id="setbordername-name-string-null-void" tabindex="-1"><code>setBorderName(name: string | null): void</code> <a class="header-anchor" href="#setbordername-name-string-null-void" aria-label="Permalink to &quot;`setBorderName(name: string | null): void`&quot;">​</a></h3><p>Sets border style name for plaques. <code>null</code> = no border.</p><h3 id="setshowinsetcontour-show-boolean-void" tabindex="-1"><code>setShowInsetContour(show: boolean): void</code> <a class="header-anchor" href="#setshowinsetcontour-show-boolean-void" aria-label="Permalink to &quot;`setShowInsetContour(show: boolean): void`&quot;">​</a></h3><p>Toggles inset contour line on headstone.</p><hr><h2 id="inscriptions" tabindex="-1">Inscriptions <a class="header-anchor" href="#inscriptions" aria-label="Permalink to &quot;Inscriptions&quot;">​</a></h2><h3 id="setinscriptions-inscriptions-line-prev-line-line-void" tabindex="-1"><code>setInscriptions(inscriptions: Line[] | ((prev: Line[]) =&gt; Line[])): void</code> <a class="header-anchor" href="#setinscriptions-inscriptions-line-prev-line-line-void" aria-label="Permalink to &quot;`setInscriptions(inscriptions: Line[] | ((prev: Line[]) =&gt; Line[])): void`&quot;">​</a></h3><p>Replaces all inscriptions. Accepts array or updater function. Normalizes line surface dimensions. Recalculates cost.</p><h3 id="addinscriptionline-patch-linepatch-string" tabindex="-1"><code>addInscriptionLine(patch?: LinePatch): string</code> <a class="header-anchor" href="#addinscriptionline-patch-linepatch-string" aria-label="Permalink to &quot;`addInscriptionLine(patch?: LinePatch): string`&quot;">​</a></h3><p>Creates a new inscription line. Returns the generated line ID. Default text: &quot;New line&quot;, font: &quot;Garamond&quot;. Color uses catalog <code>defaultColor</code>. Target surface uses current <code>selected</code> object. Auto-selects new line and recalculates cost.</p><h3 id="updateinscription-id-string-patch-partial-line-void" tabindex="-1"><code>updateInscription(id: string, patch: Partial&lt;Line&gt;): void</code> <a class="header-anchor" href="#updateinscription-id-string-patch-partial-line-void" aria-label="Permalink to &quot;`updateInscription(id: string, patch: Partial&lt;Line&gt;): void`&quot;">​</a></h3><p>Updates an existing inscription with partial data. Clamps <code>sizeMm</code> to <code>[inscriptionMinHeight, inscriptionMaxHeight]</code> and <code>rotationDeg</code> to <code>[-45°, 45°]</code>. Recalculates cost.</p><h3 id="duplicateinscription-id-string-string" tabindex="-1"><code>duplicateInscription(id: string): string</code> <a class="header-anchor" href="#duplicateinscription-id-string-string" aria-label="Permalink to &quot;`duplicateInscription(id: string): string`&quot;">​</a></h3><p>Clones an inscription and offsets it vertically to avoid overlap. Returns new ID. Uses rendered bounds from Three.js mesh for precise offset calculation.</p><h3 id="deleteinscription-id-string-void" tabindex="-1"><code>deleteInscription(id: string): void</code> <a class="header-anchor" href="#deleteinscription-id-string-void" aria-label="Permalink to &quot;`deleteInscription(id: string): void`&quot;">​</a></h3><p>Removes an inscription and auto-selects the first remaining line.</p><h3 id="setselectedinscriptionid-id-string-null-void" tabindex="-1"><code>setSelectedInscriptionId(id: string | null): void</code> <a class="header-anchor" href="#setselectedinscriptionid-id-string-null-void" aria-label="Permalink to &quot;`setSelectedInscriptionId(id: string | null): void`&quot;">​</a></h3><p>Selects an inscription for editing. Deselects motifs, additions, headstone/base. Sets <code>activePanel</code> to <code>&#39;inscription&#39;</code>.</p><h3 id="setactiveinscriptiontext-text-string-void" tabindex="-1"><code>setActiveInscriptionText(text: string): void</code> <a class="header-anchor" href="#setactiveinscriptiontext-text-string-void" aria-label="Permalink to &quot;`setActiveInscriptionText(text: string): void`&quot;">​</a></h3><p>Updates the text being edited in the input (not committed until blur/save).</p><h3 id="setinscriptionheightlimits-min-number-max-number-void" tabindex="-1"><code>setInscriptionHeightLimits(min: number, max: number): void</code> <a class="header-anchor" href="#setinscriptionheightlimits-min-number-max-number-void" aria-label="Permalink to &quot;`setInscriptionHeightLimits(min: number, max: number): void`&quot;">​</a></h3><p>Sets the valid size range for inscriptions (from product catalog).</p><h3 id="setfontloading-loading-boolean-void" tabindex="-1"><code>setFontLoading(loading: boolean): void</code> <a class="header-anchor" href="#setfontloading-loading-boolean-void" aria-label="Permalink to &quot;`setFontLoading(loading: boolean): void`&quot;">​</a></h3><p>Indicates whether fonts are currently loading.</p><h3 id="calculateinscriptioncost-void" tabindex="-1"><code>calculateInscriptionCost(): void</code> <a class="header-anchor" href="#calculateinscriptioncost-void" aria-label="Permalink to &quot;`calculateInscriptionCost(): void`&quot;">​</a></h3><p>Calculates total inscription cost based on font size as quantity and color-to-pricing mapping (Gold Gilding / Silver Gilding / Paint Fill). Sets <code>inscriptionCost</code>.</p><hr><h2 id="motifs" tabindex="-1">Motifs <a class="header-anchor" href="#motifs" aria-label="Permalink to &quot;Motifs&quot;">​</a></h2><h3 id="addmotif-svgpath-string-void" tabindex="-1"><code>addMotif(svgPath: string): void</code> <a class="header-anchor" href="#addmotif-svgpath-string-void" aria-label="Permalink to &quot;`addMotif(svgPath: string): void`&quot;">​</a></h3><p>Adds a decorative SVG motif. Generates unique ID. Color defaults to catalog <code>defaultColor</code> or white (laser) / gold (engraved). Creates default offset at center. Auto-selects and opens motif panel.</p><h3 id="removemotif-id-string-void" tabindex="-1"><code>removeMotif(id: string): void</code> <a class="header-anchor" href="#removemotif-id-string-void" aria-label="Permalink to &quot;`removeMotif(id: string): void`&quot;">​</a></h3><p>Removes a motif. Clears offset data. Clears selection if active.</p><h3 id="setmotifcolor-id-string-color-string-void" tabindex="-1"><code>setMotifColor(id: string, color: string): void</code> <a class="header-anchor" href="#setmotifcolor-id-string-color-string-void" aria-label="Permalink to &quot;`setMotifColor(id: string, color: string): void`&quot;">​</a></h3><p>Updates motif color (hex). Triggers cost recalc.</p><h3 id="setmotifref-id-string-ref-refobject-group-null-void" tabindex="-1"><code>setMotifRef(id: string, ref: RefObject&lt;Group | null&gt;): void</code> <a class="header-anchor" href="#setmotifref-id-string-ref-refobject-group-null-void" aria-label="Permalink to &quot;`setMotifRef(id: string, ref: RefObject&lt;Group | null&gt;): void`&quot;">​</a></h3><p>Stores Three.js Group ref for the rendered motif mesh.</p><h3 id="setmotifoffset-id-string-offset-partial-motifoffset-void" tabindex="-1"><code>setMotifOffset(id: string, offset: Partial&lt;MotifOffset&gt;): void</code> <a class="header-anchor" href="#setmotifoffset-id-string-offset-partial-motifoffset-void" aria-label="Permalink to &quot;`setMotifOffset(id: string, offset: Partial&lt;MotifOffset&gt;): void`&quot;">​</a></h3><p>Updates motif position/scale/rotation. Partial merge with existing offset. Auto-refreshes surface dimensions if target changes.</p><h3 id="duplicatemotif-id-string-void" tabindex="-1"><code>duplicateMotif(id: string): void</code> <a class="header-anchor" href="#duplicatemotif-id-string-void" aria-label="Permalink to &quot;`duplicateMotif(id: string): void`&quot;">​</a></h3><p>Clones a motif with offset (30px on headstone, 15% on ledger). Auto-selects clone.</p><h3 id="calculatemotifcost-void" tabindex="-1"><code>calculateMotifCost(): void</code> <a class="header-anchor" href="#calculatemotifcost-void" aria-label="Permalink to &quot;`calculateMotifCost(): void`&quot;">​</a></h3><p>Calculates total motif cost based on height and color via <code>calculateMotifPrice()</code>. Uses <code>motifPriceModel</code>. Free for laser products.</p><hr><h2 id="additions-statues-vases-applications" tabindex="-1">Additions (Statues, Vases, Applications) <a class="header-anchor" href="#additions-statues-vases-applications" aria-label="Permalink to &quot;Additions (Statues, Vases, Applications)&quot;">​</a></h2><h3 id="addaddition-id-string-void" tabindex="-1"><code>addAddition(id: string): void</code> <a class="header-anchor" href="#addaddition-id-string-void" aria-label="Permalink to &quot;`addAddition(id: string): void`&quot;">​</a></h3><p>Adds a 3D addition. Creates instance ID with timestamp. Target surface: statue/vase prefer <code>base</code> if available, falls back to <code>ledger</code> or <code>headstone</code>. Auto-selects and opens addition panel.</p><h3 id="removeaddition-id-string-void" tabindex="-1"><code>removeAddition(id: string): void</code> <a class="header-anchor" href="#removeaddition-id-string-void" aria-label="Permalink to &quot;`removeAddition(id: string): void`&quot;">​</a></h3><p>Removes an addition instance. Clears refs and offsets.</p><h3 id="hasstatue-boolean" tabindex="-1"><code>hasStatue(): boolean</code> <a class="header-anchor" href="#hasstatue-boolean" aria-label="Permalink to &quot;`hasStatue(): boolean`&quot;">​</a></h3><p>Returns whether any statue or vase is on the base surface.</p><h3 id="setbasemeshref-mesh-mesh-null-void" tabindex="-1"><code>setBaseMeshRef(mesh: Mesh | null): void</code> <a class="header-anchor" href="#setbasemeshref-mesh-mesh-null-void" aria-label="Permalink to &quot;`setBaseMeshRef(mesh: Mesh | null): void`&quot;">​</a></h3><p>Stores Three.js Mesh ref for the base (for coordinate calculations).</p><h3 id="setselectedadditionid-id-string-null-void" tabindex="-1"><code>setSelectedAdditionId(id: string | null): void</code> <a class="header-anchor" href="#setselectedadditionid-id-string-null-void" aria-label="Permalink to &quot;`setSelectedAdditionId(id: string | null): void`&quot;">​</a></h3><p>Selects an addition for editing. Deselects other objects. On mobile, navigates to <code>/select-additions</code>.</p><h3 id="setadditionref-id-string-ref-refobject-group-null-void" tabindex="-1"><code>setAdditionRef(id: string, ref: RefObject&lt;Group | null&gt;): void</code> <a class="header-anchor" href="#setadditionref-id-string-ref-refobject-group-null-void" aria-label="Permalink to &quot;`setAdditionRef(id: string, ref: RefObject&lt;Group | null&gt;): void`&quot;">​</a></h3><p>Stores Three.js Group ref for the rendered addition mesh.</p><h3 id="setadditionoffset-id-string-offset-partial-additionoffset-void" tabindex="-1"><code>setAdditionOffset(id: string, offset: Partial&lt;AdditionOffset&gt;): void</code> <a class="header-anchor" href="#setadditionoffset-id-string-offset-partial-additionoffset-void" aria-label="Permalink to &quot;`setAdditionOffset(id: string, offset: Partial&lt;AdditionOffset&gt;): void`&quot;">​</a></h3><p>Updates position/scale/rotation and optional metadata (sizeVariant, targetSurface, additionType, assetFile, etc.). Auto-refreshes surface dimensions.</p><h3 id="duplicateaddition-id-string-void" tabindex="-1"><code>duplicateAddition(id: string): void</code> <a class="header-anchor" href="#duplicateaddition-id-string-void" aria-label="Permalink to &quot;`duplicateAddition(id: string): void`&quot;">​</a></h3><p>Clones an addition with offset position based on surface and footprint width.</p><h3 id="calculateadditioncost-void" tabindex="-1"><code>calculateAdditionCost(): void</code> <a class="header-anchor" href="#calculateadditioncost-void" aria-label="Permalink to &quot;`calculateAdditionCost(): void`&quot;">​</a></h3><p>Calculates total cost by summing <code>retailPrice</code> from size variants.</p><hr><h2 id="emblems-bronze-plaques" tabindex="-1">Emblems (Bronze Plaques) <a class="header-anchor" href="#emblems-bronze-plaques" aria-label="Permalink to &quot;Emblems (Bronze Plaques)&quot;">​</a></h2><h3 id="addemblem-emblemid-string-imageurl-string-void" tabindex="-1"><code>addEmblem(emblemId: string, imageUrl: string): void</code> <a class="header-anchor" href="#addemblem-emblemid-string-imageurl-string-void" aria-label="Permalink to &quot;`addEmblem(emblemId: string, imageUrl: string): void`&quot;">​</a></h3><p>Adds a bronze plaque emblem. Default size from <code>EMBLEM_SIZES</code> config. Auto-selects and opens emblem panel.</p><h3 id="removeemblem-id-string-void" tabindex="-1"><code>removeEmblem(id: string): void</code> <a class="header-anchor" href="#removeemblem-id-string-void" aria-label="Permalink to &quot;`removeEmblem(id: string): void`&quot;">​</a></h3><p>Removes an emblem. Clears offset data and selection.</p><h3 id="setselectedemblemid-id-string-null-void" tabindex="-1"><code>setSelectedEmblemId(id: string | null): void</code> <a class="header-anchor" href="#setselectedemblemid-id-string-null-void" aria-label="Permalink to &quot;`setSelectedEmblemId(id: string | null): void`&quot;">​</a></h3><p>Selects an emblem for editing.</p><h3 id="setemblemref-id-string-ref-refobject-group-null-void" tabindex="-1"><code>setEmblemRef(id: string, ref: RefObject&lt;Group | null&gt;): void</code> <a class="header-anchor" href="#setemblemref-id-string-ref-refobject-group-null-void" aria-label="Permalink to &quot;`setEmblemRef(id: string, ref: RefObject&lt;Group | null&gt;): void`&quot;">​</a></h3><p>Stores Three.js Group ref for the rendered emblem.</p><h3 id="duplicateemblem-id-string-void" tabindex="-1"><code>duplicateEmblem(id: string): void</code> <a class="header-anchor" href="#duplicateemblem-id-string-void" aria-label="Permalink to &quot;`duplicateEmblem(id: string): void`&quot;">​</a></h3><p>Clones an emblem with 20mm offset.</p><h3 id="setemblemoffset-id-string-offset-partial-emblemoffset-void" tabindex="-1"><code>setEmblemOffset(id: string, offset: Partial&lt;EmblemOffset&gt;): void</code> <a class="header-anchor" href="#setemblemoffset-id-string-offset-partial-emblemoffset-void" aria-label="Permalink to &quot;`setEmblemOffset(id: string, offset: Partial&lt;EmblemOffset&gt;): void`&quot;">​</a></h3><p>Updates emblem position/size/rotation/flip. Auto-refreshes dimensions.</p><h3 id="calculateemblemcost-void" tabindex="-1"><code>calculateEmblemCost(): void</code> <a class="header-anchor" href="#calculateemblemcost-void" aria-label="Permalink to &quot;`calculateEmblemCost(): void`&quot;">​</a></h3><p>Flat rate: $1.09 (109 cents) per emblem. Sets <code>emblemCost = count × 109</code>.</p><hr><h2 id="images-photos" tabindex="-1">Images (Photos) <a class="header-anchor" href="#images-photos" aria-label="Permalink to &quot;Images (Photos)&quot;">​</a></h2><h3 id="addimage-image-imagedata-void" tabindex="-1"><code>addImage(image: ImageData): void</code> <a class="header-anchor" href="#addimage-image-imagedata-void" aria-label="Permalink to &quot;`addImage(image: ImageData): void`&quot;">​</a></h3><p>Adds a photograph to the design. For ledger surface: resets position to center. Clears <code>cropCanvasData</code> after adding.</p><h3 id="removeimage-id-string-void" tabindex="-1"><code>removeImage(id: string): void</code> <a class="header-anchor" href="#removeimage-id-string-void" aria-label="Permalink to &quot;`removeImage(id: string): void`&quot;">​</a></h3><p>Removes an image. Clears selection if active.</p><h3 id="duplicateimage-id-string-void" tabindex="-1"><code>duplicateImage(id: string): void</code> <a class="header-anchor" href="#duplicateimage-id-string-void" aria-label="Permalink to &quot;`duplicateImage(id: string): void`&quot;">​</a></h3><p>Clones with offset (~10% on ledger, 20px on headstone/base). Auto-selects clone.</p><h3 id="updateimageposition-id-string-xpos-number-ypos-number-void" tabindex="-1"><code>updateImagePosition(id: string, xPos: number, yPos: number): void</code> <a class="header-anchor" href="#updateimageposition-id-string-xpos-number-ypos-number-void" aria-label="Permalink to &quot;`updateImagePosition(id: string, xPos: number, yPos: number): void`&quot;">​</a></h3><p>Updates image X/Y position. Clears <code>coordinateSpace</code>.</p><h3 id="updateimagesize-id-string-widthmm-number-heightmm-number-void" tabindex="-1"><code>updateImageSize(id: string, widthMm: number, heightMm: number): void</code> <a class="header-anchor" href="#updateimagesize-id-string-widthmm-number-heightmm-number-void" aria-label="Permalink to &quot;`updateImageSize(id: string, widthMm: number, heightMm: number): void`&quot;">​</a></h3><p>Updates image dimensions in mm. Triggers cost recalc.</p><h3 id="updateimagesizevariant-id-string-sizevariant-number-void" tabindex="-1"><code>updateImageSizeVariant(id: string, sizeVariant: number): void</code> <a class="header-anchor" href="#updateimagesizevariant-id-string-sizevariant-number-void" aria-label="Permalink to &quot;`updateImageSizeVariant(id: string, sizeVariant: number): void`&quot;">​</a></h3><p>Updates size variant index (maps to predefined sizes). Triggers cost recalc.</p><h3 id="updateimagerotation-id-string-rotationz-number-void" tabindex="-1"><code>updateImageRotation(id: string, rotationZ: number): void</code> <a class="header-anchor" href="#updateimagerotation-id-string-rotationz-number-void" aria-label="Permalink to &quot;`updateImageRotation(id: string, rotationZ: number): void`&quot;">​</a></h3><p>Updates rotation angle in degrees.</p><h3 id="setselectedimageid-id-string-null-void" tabindex="-1"><code>setSelectedImageId(id: string | null): void</code> <a class="header-anchor" href="#setselectedimageid-id-string-null-void" aria-label="Permalink to &quot;`setSelectedImageId(id: string | null): void`&quot;">​</a></h3><p>Selects an image. Deselects all other objects.</p><h3 id="setcropcanvasdata-data-cropcanvasdata-null-void" tabindex="-1"><code>setCropCanvasData(data: CropCanvasData | null): void</code> <a class="header-anchor" href="#setcropcanvasdata-data-cropcanvasdata-null-void" aria-label="Permalink to &quot;`setCropCanvasData(data: CropCanvasData | null): void`&quot;">​</a></h3><p>Stores active crop/mask/color/rotation state for the image crop UI.</p><h3 id="calculateimagecost-promise-void" tabindex="-1"><code>calculateImageCost(): Promise&lt;void&gt;</code> <a class="header-anchor" href="#calculateimagecost-promise-void" aria-label="Permalink to &quot;`calculateImageCost(): Promise&lt;void&gt;`&quot;">​</a></h3><p><strong>Async.</strong> Fetches pricing map, then calculates total cost for all images by type and dimensions. Sets <code>imageCost</code>.</p><hr><h2 id="ui-view-state" tabindex="-1">UI &amp; View State <a class="header-anchor" href="#ui-view-state" aria-label="Permalink to &quot;UI &amp; View State&quot;">​</a></h2><h3 id="setselected-part-part-void" tabindex="-1"><code>setSelected(part: Part): void</code> <a class="header-anchor" href="#setselected-part-part-void" aria-label="Permalink to &quot;`setSelected(part: Part): void`&quot;">​</a></h3><p>Selects which monument part the user is interacting with. Deselects all other editing contexts.</p><h3 id="setactivepanel-p-panelname-void" tabindex="-1"><code>setActivePanel(p: PanelName): void</code> <a class="header-anchor" href="#setactivepanel-p-panelname-void" aria-label="Permalink to &quot;`setActivePanel(p: PanelName): void`&quot;">​</a></h3><p>Sets the currently active UI panel.</p><h3 id="seteditingobject-obj-headstone-base-ledger-kerbset-void" tabindex="-1"><code>setEditingObject(obj: &#39;headstone&#39; | &#39;base&#39; | &#39;ledger&#39; | &#39;kerbset&#39;): void</code> <a class="header-anchor" href="#seteditingobject-obj-headstone-base-ledger-kerbset-void" aria-label="Permalink to &quot;`setEditingObject(obj: &#39;headstone&#39; | &#39;base&#39; | &#39;ledger&#39; | &#39;kerbset&#39;): void`&quot;">​</a></h3><p>Sets which surface the user is focused on (persists across panel changes).</p><h3 id="setnavto-fn-navfn-void" tabindex="-1"><code>setNavTo(fn: NavFn): void</code> <a class="header-anchor" href="#setnavto-fn-navfn-void" aria-label="Permalink to &quot;`setNavTo(fn: NavFn): void`&quot;">​</a></h3><p>Stores the navigation function for client-side routing (injected by app init).</p><h3 id="openinscriptions-id-string-null-void" tabindex="-1"><code>openInscriptions(id: string | null): void</code> <a class="header-anchor" href="#openinscriptions-id-string-null-void" aria-label="Permalink to &quot;`openInscriptions(id: string | null): void`&quot;">​</a></h3><p>Opens the inscription edit panel and navigates to <code>/inscriptions</code>.</p><h3 id="opensizepanel-void" tabindex="-1"><code>openSizePanel(): void</code> <a class="header-anchor" href="#opensizepanel-void" aria-label="Permalink to &quot;`openSizePanel(): void`&quot;">​</a></h3><p>Opens the size panel and navigates to <code>/select-size</code>.</p><h3 id="openadditionspanel-void" tabindex="-1"><code>openAdditionsPanel(): void</code> <a class="header-anchor" href="#openadditionspanel-void" aria-label="Permalink to &quot;`openAdditionsPanel(): void`&quot;">​</a></h3><p>Opens the additions panel and navigates to <code>/select-additions</code>.</p><h3 id="closeinscriptions-void" tabindex="-1"><code>closeInscriptions(): void</code> <a class="header-anchor" href="#closeinscriptions-void" aria-label="Permalink to &quot;`closeInscriptions(): void`&quot;">​</a></h3><p>Closes inscriptions panel and clears inscription selection.</p><h3 id="toggleviewmode-void" tabindex="-1"><code>toggleViewMode(): void</code> <a class="header-anchor" href="#toggleviewmode-void" aria-label="Permalink to &quot;`toggleViewMode(): void`&quot;">​</a></h3><p>Toggles between 3D and 2D view modes.</p><h3 id="setloading-loading-boolean-void" tabindex="-1"><code>setLoading(loading: boolean): void</code> <a class="header-anchor" href="#setloading-loading-boolean-void" aria-label="Permalink to &quot;`setLoading(loading: boolean): void`&quot;">​</a></h3><p>Sets global loading indicator flag.</p><h3 id="setismaterialchange-ismaterialchange-boolean-void" tabindex="-1"><code>setIsMaterialChange(isMaterialChange: boolean): void</code> <a class="header-anchor" href="#setismaterialchange-ismaterialchange-boolean-void" aria-label="Permalink to &quot;`setIsMaterialChange(isMaterialChange: boolean): void`&quot;">​</a></h3><p>Indicates a material change animation is in progress.</p><hr><h2 id="design-control" tabindex="-1">Design Control <a class="header-anchor" href="#design-control" aria-label="Permalink to &quot;Design Control&quot;">​</a></h2><h3 id="resetdesign-void" tabindex="-1"><code>resetDesign(): void</code> <a class="header-anchor" href="#resetdesign-void" aria-label="Permalink to &quot;`resetDesign(): void`&quot;">​</a></h3><p>Clears the entire design to a blank slate. Resets: inscriptions, additions, motifs, emblems, images, crops, selections, panels, visibility, dimensions to defaults (900×900mm). Does NOT reset: product ID, catalog, material choices.</p>',209)])])}const u=t(d,[["render",s]]);export{p as __pageData,u as default};
